"""Density probes for the group generated by generic-family A-matrices.

Question: do random A-matrices from the generic k-addable family (block
widths/heights ≥ 2, via fourier.amatrix.a_matrix_generic4/8) generate a
group that looks dense in O(N)?  Two probes, sharing the same sampler:

- --mode commutant: stack the commutant equations A·X = X·A for every
  sampled matrix and compute the nullspace dimension.  Dimension 1 (scalars
  only) means the sample acts irreducibly — a necessary condition for
  density.
- --mode mixing: sample random length-L products P of the matrices and
  estimate the rank of span{vec(P − I)} (or vec(log P) with --method logm).
  Full rank means the products explore the whole matrix space.

Supports report.md, "The Core Unsolved Problem" (the closing observation
that A-matrices "behave like generic orthogonals" — these probes found no
hidden invariant structure).

Expected result: commutant nullspace dimension 1; mixing rank full (N² for
the N×N vec space).

Merged from commutant_heuristic.py and mixing_test.py, whose sampling
helpers were identical.
"""

from __future__ import annotations

import argparse
import random

import numpy as np
import sympy as sp
from scipy.linalg import logm, null_space

from fourier.amatrix import a_matrix_generic4, a_matrix_generic8


# ── sampling generic-family parameters ─────────────────────────────────────────
#
# A generic 4-addable diagram is three stacked blocks: widths w1..w3, heights
# h1..h3, row lengths (w1+w2+w3), (w2+w3), (w3); its size is Σ h_i·(Σ_{j≥i} w_j).
# The symbolic construction assumes w_i, h_i ≥ 2 (removing a corner never
# merges blocks), which is why w_min/h_min default to 2.


def _size_from_params(w1, w2, w3, h1, h2, h3) -> int:
    return (w1 + w2 + w3) * h1 + (w2 + w3) * h2 + w3 * h3


def _candidate_triples(max_size: int, w_min: int, h_min: int) -> list[tuple[int, int, int]]:
    triples: list[tuple[int, int, int]] = []
    for w3 in range(w_min, max_size // 3 + 1):
        max_w2 = (max_size - 3 * w3) // 2
        for w2 in range(w_min, max_w2 + 1):
            max_w1 = max_size - 2 * w2 - 3 * w3
            for w1 in range(w_min, max_w1 + 1):
                if _size_from_params(w1, w2, w3, h_min, h_min, h_min) <= max_size:
                    triples.append((w1, w2, w3))
    return triples


def _random_h_tuple(
    rng: random.Random, w1: int, w2: int, w3: int, max_size: int, h_min: int
) -> tuple[int, int, int] | None:
    denom1, denom2, denom3 = w1 + w2 + w3, w2 + w3, w3

    h1_max = (max_size - denom2 * h_min - denom3 * h_min) // denom1
    if h1_max < h_min:
        return None
    h1 = rng.randint(h_min, h1_max)

    h2_max = (max_size - denom1 * h1 - denom3 * h_min) // denom2
    if h2_max < h_min:
        return None
    h2 = rng.randint(h_min, h2_max)

    h3_max = (max_size - denom1 * h1 - denom2 * h2) // denom3
    if h3_max < h_min:
        return None
    h3 = rng.randint(h_min, h3_max)

    return h1, h2, h3


def sample_params_4(
    count: int, max_size: int, seed: int, h_min: int, w_min: int
) -> list[tuple[int, ...]]:
    """Random (w1, w2, w3, h1, h2, h3) tuples with diagram size ≤ max_size."""
    triples = _candidate_triples(max_size, w_min, h_min)
    if not triples:
        return []
    rng = random.Random() if seed == 0 else random.Random(seed)
    params: list[tuple[int, ...]] = []
    max_tries = max(1000, count * 50)
    tries = 0
    while len(params) < count and tries < max_tries:
        tries += 1
        w1, w2, w3 = rng.choice(triples)
        h_tuple = _random_h_tuple(rng, w1, w2, w3, max_size, h_min)
        if h_tuple is None:
            continue
        params.append((w1, w2, w3, *h_tuple))
    return params


def sample_params_8(
    count: int, max_size: int, seed: int, h_min: int, w_min: int
) -> list[tuple[int, ...]]:
    """Random (w1..w7, h1..h7) tuples with diagram size ≤ max_size."""
    rng = random.Random() if seed == 0 else random.Random(seed)
    params: list[tuple[int, ...]] = []
    max_tries = max(2000, count * 80)
    tries = 0

    if max_size < 28 * w_min * h_min:
        return []

    weights = list(range(1, 8))

    while len(params) < count and tries < max_tries:
        tries += 1
        # Sample widths with the linear constraint h_min·Σ j·w_j ≤ max_size.
        budget = max_size // h_min
        widths: list[int] = []
        used = 0
        for idx, weight in enumerate(weights, start=1):
            remaining_min = sum(weights[idx:]) * w_min
            max_w = (budget - used - remaining_min) // weight
            if max_w < w_min:
                widths = []
                break
            widths.append(rng.randint(w_min, max_w))
            used += weight * widths[-1]
        if not widths:
            continue

        # Suffix sums S_i = Σ_{j≥i} w_j are the row lengths per block.
        suffix = [0] * 8
        for i in range(6, -1, -1):
            suffix[i] = suffix[i + 1] + widths[i]
        weights_h = suffix[:7]

        # Sample heights with the constraint Σ S_i·h_i ≤ max_size.
        heights: list[int] = []
        used_size = 0
        for i, wgt in enumerate(weights_h):
            remaining_min = sum(weights_h[i + 1 :]) * h_min
            max_h = (max_size - used_size - remaining_min) // wgt
            if max_h < h_min:
                heights = []
                break
            heights.append(rng.randint(h_min, max_h))
            used_size += wgt * heights[-1]
        if not heights:
            continue

        params.append((*widths, *heights))

    return params


def sample_matrices(args: argparse.Namespace, count: int) -> list[np.ndarray]:
    """`count` numeric A-matrices from the generic family named by --num-qubits."""
    if args.num_qubits == 3:
        A_sym, symbols = a_matrix_generic8()
        params = sample_params_8(count, args.max_size, args.seed, args.h_min, args.w_min)
    else:
        A_sym, symbols = a_matrix_generic4()
        params = sample_params_4(count, args.max_size, args.seed, args.h_min, args.w_min)

    if not params:
        msg = "No valid samples fit the max-size constraint."
        if args.num_qubits == 3:
            msg += f" (min size is {28 * args.w_min * args.h_min} for 3 qubits)."
        raise SystemExit(msg)
    if len(params) < count:
        print(f"Warning: only {len(params)} samples fit max size {args.max_size}.")

    A_func = sp.lambdify(symbols, A_sym, "numpy")
    mats = []
    eye = None
    for param in params:
        A_val = np.array(A_func(*param), dtype=complex)
        if eye is None:
            eye = np.eye(A_val.shape[0], dtype=complex)
        if args.require_unitary and not np.allclose(A_val.conj().T @ A_val, eye, atol=1e-6):
            continue
        mats.append(A_val)
    if not mats:
        raise SystemExit("No valid matrices generated.")
    return mats


# ── mode: commutant ────────────────────────────────────────────────────────────


def run_commutant(mats: list[np.ndarray], args: argparse.Namespace) -> None:
    n = mats[0].shape[0]
    eye = np.eye(n, dtype=complex)
    system = np.vstack([np.kron(A, eye) - np.kron(eye, A.T) for A in mats])
    ns = null_space(system, rcond=args.nullspace_rcond)
    dim = ns.shape[1]

    print(f"Commutant nullspace dimension: {dim}")
    if dim > 1:
        print("Warning: nontrivial commuting operator detected; likely not dense.")
    else:
        print("Commutant is trivial; heuristic density test passes.")


# ── mode: mixing ───────────────────────────────────────────────────────────────


def run_mixing(mats: list[np.ndarray], args: argparse.Namespace) -> None:
    rng = random.Random() if args.seed == 0 else random.Random(args.seed + 1)
    n = mats[0].shape[0]
    eye = np.eye(n, dtype=complex)

    vecs = []
    for _ in range(args.num_products):
        P = eye
        for _ in range(args.length):
            P = mats[rng.randrange(len(mats))] @ P
        M = logm(P) if args.method == "logm" else P - eye
        vecs.append(M.reshape(-1))

    V = np.vstack(vecs)
    svals = np.linalg.svd(V, compute_uv=False)
    rank = int(np.sum(svals > args.rank_tol))
    full_rank = min(V.shape)

    print(f"Collected {len(vecs)} products of length {args.length}")
    print(f"Matrix size: {n}x{n}; vec dimension: {n * n}")
    print(f"Rank estimate (tol={args.rank_tol:g}): {rank} / {full_rank}")
    print(f"Top singular values: {svals[: args.svd_top]}")
    print(f"Smallest singular value: {svals[-1]:.6g}")

    if rank < full_rank:
        print("Rank deficient: indicates a hidden invariant subspace.")
    else:
        print("Full rank: products explore the space; good sign for density.")


# ── CLI ────────────────────────────────────────────────────────────────────────


def parse_args() -> argparse.Namespace:
    p = argparse.ArgumentParser(
        description=__doc__, formatter_class=argparse.RawDescriptionHelpFormatter
    )
    p.add_argument("--mode", choices=("commutant", "mixing"), default="commutant",
                   help="Which probe to run (default: commutant).")
    p.add_argument("--num-qubits", type=int, choices=(2, 3), default=2,
                   help="Number of qubits (2 -> 4x4, 3 -> 8x8).")
    p.add_argument("--count", type=int, default=None,
                   help="Number of base matrices (default: 12 commutant, 8 mixing).")
    p.add_argument("--max-size", type=int, default=60,
                   help="Max diagram size to sample (default: 60).")
    p.add_argument("--seed", type=int, default=0,
                   help="Random seed (0 for random).")
    p.add_argument("--w-min", type=int, default=2,
                   help="Minimum block width w_i; < 2 invalidates the symbolic "
                        "generic-family assumptions (default: 2).")
    p.add_argument("--h-min", type=int, default=2,
                   help="Minimum block height h_i (default: 2).")
    p.add_argument("--require-unitary", action="store_true",
                   help="Skip matrices that are not numerically unitary (slower).")
    # commutant mode
    p.add_argument("--nullspace-rcond", type=float, default=1e-10,
                   help="Relative condition threshold for the nullspace (commutant mode).")
    # mixing mode
    p.add_argument("--length", type=int, default=6,
                   help="Product length L (mixing mode).")
    p.add_argument("--num-products", type=int, default=200,
                   help="Number of products to sample (mixing mode).")
    p.add_argument("--method", choices=("logm", "diff"), default="diff",
                   help="Use M=logm(P) or M=P−I (mixing mode).")
    p.add_argument("--rank-tol", type=float, default=1e-8,
                   help="Singular-value threshold for rank estimation (mixing mode).")
    p.add_argument("--svd-top", type=int, default=12,
                   help="Number of top singular values to print (mixing mode).")
    return p.parse_args()


def main() -> None:
    args = parse_args()
    if args.w_min < 2 or args.h_min < 2:
        print("Warning: w_min/h_min < 2 can invalidate the symbolic "
              "removable/addable assumptions.")

    count = args.count if args.count is not None else (12 if args.mode == "commutant" else 8)
    mats = sample_matrices(args, count)
    print(f"Sampled {len(mats)} generic {mats[0].shape[0]}×{mats[0].shape[0]} A-matrices "
          f"(mode: {args.mode})")

    if args.mode == "commutant":
        run_commutant(mats, args)
    else:
        run_mixing(mats, args)


if __name__ == "__main__":
    main()
